import java.io.IOException;

public class SecureCommandExecutionDemo {

    public static void main(String[] args) {
        String userInput = "127.0.0.1; ls";

        try {
            // Splitting user input to separate command and arguments
            String[] command = { "ping", userInput };

            // Using ProcessBuilder for secure execution
            ProcessBuilder processBuilder = new ProcessBuilder(command);

            // Redirecting error stream to output stream
            processBuilder.redirectErrorStream(true);

            // Start the process
            Process process = processBuilder.start();

            // Reading the output of the command
            java.util.Scanner scanner = new java.util.Scanner(process.getInputStream());
            while (scanner.hasNextLine()) {
                System.out.println(scanner.nextLine());
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

